<?php namespace App\Repositories\Hr;use App\Repositories\BaseRepository;use App\Models\Hr\JobApplication;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class JobApplicationRepository extends BaseRepository{    public function __construct(JobApplication $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByRecruitment(int $recruitmentId): Collection    {        return $this->findByField('recruitment_id', $recruitmentId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByEmail(string $email): ?JobApplication    {        return $this->query()->where('email', $email)->first();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('applied_date', [$startDate, $endDate])->get();    }    public function getPendingApplications(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getShortlistedApplications(): Collection    {        return $this->query()->where('status', 'shortlisted')->get();    }    public function searchApplications(string $keyword): Collection    {        return $this->query()->where('first_name', 'like', "%{$keyword}%")->orWhere('last_name', 'like', "%{$keyword}%")->orWhere('email', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->get();    }    public function shortlist(int $id): bool    {        return $this->update($id, ['status' => 'shortlisted', 'shortlisted_at' => now()]);    }    public function reject(int $id, ?string $reason = null): bool    {        $data = ['status' => 'rejected'];        if ($reason) {            $data['rejection_reason'] = $reason;        }        return $this->update($id, $data);    }    public function hire(int $id): bool    {        return $this->update($id, ['status' => 'hired', 'hired_at' => now()]);    }}